insert into public.recipes (slug, title, icon, category, time_label, description, region, state, data) values
  ('arroz_com_pequi', 'Arroz com Pequi', '🍚', 'Almoço · Goiano', '35 min', 'Arroz goiano tradicional refogado com pequi e frango caipira desfiado.', 'centro_oeste', 'GO', '{"ings":[{"n":"Arroz branco cru","a":"1 xícara"},{"n":"Pequi cozido (caroços)","a":"6 unidades"},{"n":"Frango caipira desfiado","a":"200 g"},{"n":"Alho picado","a":"3 dentes"},{"n":"Cebola picada","a":"1/2 unidade"},{"n":"Óleo","a":"1 col sopa"},{"n":"Sal, pimenta-do-reino","a":"a gosto"}],"steps":["Refogue cebola e alho no óleo até dourar.","Acrescente o pequi cozido e refogue por 2 minutos.","Adicione o arroz lavado e mexa até os grãos absorverem o óleo.","Despeje 2 xícaras de água fervente e sal; tampe e cozinhe em fogo baixo por 15 min.","Quando o arroz estiver pronto, misture o frango desfiado já temperado.","Deixe descansar tampado por 3 minutos antes de servir."],"tip":"Roa o pequi ao redor do caroço — NUNCA morda direto. Os espinhos internos machucam."}'::jsonb),
  ('galinhada_goiana', 'Galinhada Goiana', '🍲', 'Almoço · Especial', '1h', 'Arroz cozido junto com frango, açafrão e pequi — prato único clássico de Goiás.', 'centro_oeste', 'GO', '{"ings":[{"n":"Frango caipira em pedaços","a":"600 g"},{"n":"Arroz branco cru","a":"1,5 xícaras"},{"n":"Pequi cozido","a":"8 caroços"},{"n":"Açafrão-da-terra (cúrcuma)","a":"1 col chá"},{"n":"Alho, cebola, cebolinha","a":"a gosto"},{"n":"Caldo de frango","a":"3 xícaras"},{"n":"Óleo, sal, pimenta","a":"a gosto"}],"steps":["Tempere o frango com alho, sal e pimenta; deixe pegar gosto por 20 min.","Doure os pedaços em panela de pressão com um fio de óleo.","Acrescente cebola, açafrão e pequi; refogue por 3 minutos.","Junte o arroz cru e mexa até envolver tudo.","Cubra com caldo fervente, tampe e cozinhe em pressão por 12 min.","Finalize com cebolinha picada e sirva bem quente."],"tip":"Açafrão autêntico goiano é a cúrcuma ralada (não o açafrão espanhol). Intensifica cor e sabor."}'::jsonb),
  ('empadao_goiano', 'Empadão Goiano', '🥧', 'Almoço · Especial', '1h30', 'Torta salgada goiana com recheio de frango, guariroba, linguiça, ovo e azeitona.', 'centro_oeste', 'GO', '{"ings":[{"n":"Massa podre (farinha + banha + ovo)","a":"600 g"},{"n":"Frango desfiado cozido","a":"300 g"},{"n":"Guariroba picada e dessalgada","a":"1 xícara"},{"n":"Linguiça calabresa picada","a":"100 g"},{"n":"Ovos cozidos fatiados","a":"2 unidades"},{"n":"Azeitonas verdes","a":"12 unidades"},{"n":"Cebola, alho, cheiro-verde","a":"a gosto"}],"steps":["Refogue cebola e alho; doure a linguiça e junte o frango desfiado.","Acrescente a guariroba já dessalgada e cozinhe por 5 minutos.","Forre uma forma untada com 2/3 da massa (fundo e laterais).","Distribua o recheio, ovos fatiados e azeitonas por cima.","Cubra com o restante da massa; pincele gema batida.","Asse em forno pré-aquecido a 180 °C por 45 min até dourar."],"tip":"Guariroba precisa ser cozida e dessalgada em 2 águas antes — se não, amarga o empadão inteiro."}'::jsonb),
  ('mojica_de_pintado', 'Mojica de Pintado', '🐟', 'Almoço · Pantaneiro', '45 min', 'Ensopado pantaneiro de pintado com mandioca amassada e caldo cremoso.', 'centro_oeste', 'MT', '{"ings":[{"n":"Pintado em postas","a":"500 g"},{"n":"Mandioca descascada","a":"400 g"},{"n":"Tomate picado sem pele","a":"2 unidades"},{"n":"Cebola, alho, pimentão","a":"a gosto"},{"n":"Cheiro-verde, coentro","a":"1 maço"},{"n":"Limão, sal, pimenta","a":"a gosto"}],"steps":["Tempere as postas de pintado com limão, sal e alho; reserve 15 min.","Cozinhe a mandioca em água até ficar bem macia; amasse metade dela.","Refogue cebola, alho e pimentão numa panela grande.","Acrescente tomate e cozinhe até desmanchar.","Junte as postas e os pedaços de mandioca; cubra com água morna.","Cozinhe em fogo baixo por 15 min. Incorpore a mandioca amassada para encorpar.","Finalize com coentro e cheiro-verde; sirva imediatamente."],"tip":"A mandioca amassada é o segredo do caldo grosso — pode usar um fubá fino como alternativa."}'::jsonb),
  ('soba_campo_grande', 'Sobá de Campo Grande', '🍜', 'Almoço · Sul-mato-grossense', '40 min', 'Macarrão japonês servido em caldo com frango desfiado, ovo, cebolinha — prato oficial de Campo Grande.', 'centro_oeste', 'MS', '{"ings":[{"n":"Macarrão sobá (yakissoba)","a":"200 g"},{"n":"Peito de frango cozido e desfiado","a":"200 g"},{"n":"Caldo de frango caseiro","a":"1 litro"},{"n":"Ovos cozidos","a":"2 unidades"},{"n":"Cebolinha picada","a":"1 maço"},{"n":"Gengibre ralado, alho","a":"a gosto"},{"n":"Shoyu, sal","a":"a gosto"}],"steps":["Aqueça o caldo de frango; adicione gengibre ralado, alho e um fio de shoyu.","Ferva e cozinhe o macarrão sobá diretamente no caldo por 4 min.","Separe os bowls; distribua o frango desfiado por cima.","Adicione metade de um ovo cozido em cada bowl.","Finalize com cebolinha picada fresca; sirva fumegante."],"tip":"O sobá veio com imigrantes okinawanos e virou patrimônio cultural de MS — não é ramen nem lámen."}'::jsonb),
  ('soba_light', 'Sobá Light', '🥢', 'Jantar · Leve', '25 min', 'Versão leve do sobá — menos macarrão, mais frango magro e legumes.', 'centro_oeste', 'MS', '{"ings":[{"n":"Macarrão sobá integral","a":"120 g"},{"n":"Peito de frango grelhado em tiras","a":"150 g"},{"n":"Caldo de frango desnatado","a":"800 ml"},{"n":"Cenoura em palitos, broto de feijão","a":"a gosto"},{"n":"Cebolinha, gengibre, shoyu light","a":"a gosto"}],"steps":["Aqueça o caldo com gengibre ralado e um fio de shoyu light.","Cozinhe o macarrão integral no caldo por 5 min.","Nos últimos 2 min, junte cenoura em palitos e broto de feijão.","Monte o bowl com o frango grelhado em tiras por cima.","Finalize com cebolinha; sirva imediatamente."],"tip":"Trocar o shoyu comum pelo light corta ~60% do sódio sem mudar o sabor."}'::jsonb),
  ('costela_pantaneira', 'Costela de Chão Pantaneira', '🥩', 'Almoço · Especial', '4h', 'Costela bovina assada lentamente na brasa, tradição pantaneira — acompanha mandioca assada.', 'centro_oeste', 'MT', '{"ings":[{"n":"Costela bovina (ripa ou ponta)","a":"1,2 kg"},{"n":"Sal grosso","a":"3 col sopa"},{"n":"Alho socado","a":"6 dentes"},{"n":"Mandioca em pedaços","a":"600 g"},{"n":"Cerveja ou água","a":"200 ml"}],"steps":["Fure a costela com faca e esfregue sal grosso e alho; deixe descansar 30 min.","No forno: asse a 160 °C coberta com papel alumínio por 3 horas.","Abra o papel, regue com cerveja/água e volte ao forno a 200 °C por mais 40 min.","Em paralelo, cozinhe a mandioca em água com sal por 25 min.","Leve a mandioca cozida ao forno junto com a costela nos últimos 20 min para dourar.","Sirva a carne em lascas soltas; mandioca tostada ao lado."],"tip":"Costela no fogo de chão leva 8h a 12h; no forno convencional, 3h a 4h resolve bem."}'::jsonb),
  ('maria_isabel', 'Maria-Isabel', '🍛', 'Almoço · Mato-grossense', '40 min', 'Arroz cozido com carne seca desfiada — típico do Mato Grosso, prato de boiadeiro.', 'centro_oeste', 'MT', '{"ings":[{"n":"Carne seca dessalgada e desfiada","a":"250 g"},{"n":"Arroz branco cru","a":"1 xícara"},{"n":"Cebola, alho, tomate","a":"a gosto"},{"n":"Caldo da carne seca","a":"2 xícaras"},{"n":"Cheiro-verde, banha ou óleo","a":"a gosto"}],"steps":["Dessalgue a carne seca em 2 águas; cozinhe em pressão por 30 min e desfie.","Refogue cebola e alho na banha; acrescente tomate picado.","Junte a carne desfiada e refogue por 3 minutos.","Adicione o arroz lavado e mexa bem.","Cubra com o caldo da carne (ou água quente) e cozinhe por 15 min.","Finalize com cheiro-verde picado antes de servir."],"tip":"Aproveite o caldo de cozinhar a carne seca — dá muito mais sabor que água pura."}'::jsonb),
  ('bife_pantaneiro', 'Bife Pantaneiro com Farofa de Banana', '🥩', 'Almoço · Pantaneiro', '30 min', 'Bife na chapa ao estilo pantaneiro servido com farofa crocante de banana-da-terra.', 'centro_oeste', 'MT', '{"ings":[{"n":"Filé mignon ou alcatra em bifes","a":"300 g"},{"n":"Banana-da-terra madura","a":"2 unidades"},{"n":"Farinha de mandioca torrada","a":"1 xícara"},{"n":"Manteiga","a":"2 col sopa"},{"n":"Alho, cebola, sal, pimenta","a":"a gosto"}],"steps":["Tempere os bifes com sal, pimenta e alho amassado.","Grelhe em chapa ou frigideira bem quente por 2 min cada lado.","Para a farofa: derreta manteiga, doure cebola e adicione banana em rodelas.","Quando a banana amolecer, misture a farinha e mexa até ficar crocante.","Sirva o bife sobre a farofa ainda quente."],"tip":"Use banana madura mas firme — se passar do ponto, vira purê na farofa."}'::jsonb),
  ('pacu_na_folha', 'Pacu Assado na Folha de Bananeira', '🐟', 'Almoço · Pantaneiro', '50 min', 'Pacu inteiro ou em postas, assado embrulhado em folha de bananeira — fica suculento.', 'centro_oeste', 'MT', '{"ings":[{"n":"Pacu em postas ou inteiro","a":"600 g"},{"n":"Folhas de bananeira grandes","a":"2 unidades"},{"n":"Limão, alho, cebolinha","a":"a gosto"},{"n":"Pimenta-de-cheiro, azeite","a":"a gosto"}],"steps":["Lave as folhas de bananeira e passe sobre a chama rapidamente para amolecer.","Tempere o peixe com limão, alho, sal e pimenta; deixe 15 min.","Regue com azeite e distribua cebolinha por cima.","Embrulhe firme nas folhas de bananeira formando um pacote.","Asse no forno a 200 °C por 35 min (ou na brasa por 25 min).","Abra o pacote na mesa — o aroma é parte da experiência."],"tip":"Se não achar folha de bananeira, papel manteiga + papel alumínio funciona (perde o aroma)."}'::jsonb),
  ('caldeirada_pantaneira', 'Caldeirada Pantaneira', '🍲', 'Almoço · Pantaneiro', '45 min', 'Ensopado rico com pintado, pacu, legumes e batatas — prato de rio do Pantanal.', 'centro_oeste', 'MT', '{"ings":[{"n":"Pintado em postas","a":"300 g"},{"n":"Pacu em postas","a":"300 g"},{"n":"Batata inglesa em cubos","a":"3 unidades"},{"n":"Cenoura, cebola, tomate, pimentão","a":"a gosto"},{"n":"Coentro, cheiro-verde","a":"1 maço"},{"n":"Azeite, sal, pimenta, limão","a":"a gosto"}],"steps":["Tempere as postas com limão, sal e pimenta; reserve.","Refogue cebola, alho e pimentão em azeite numa panela larga.","Acrescente tomate em cubos e cozinhe até desmanchar.","Faça camadas: batata, cenoura, peixe, por cima mais tomate.","Cubra com água fervente até o nível da batata; tampe.","Cozinhe em fogo médio por 25 min sem mexer (só sacuda a panela).","Finalize com coentro fresco."],"tip":"Não mexa com colher — quebra os pedaços de peixe. Só balance a panela."}'::jsonb),
  ('caldo_de_piranha', 'Caldo de Piranha', '🥣', 'Jantar · Pantaneiro', '50 min', 'Caldo forte de piranha — famoso pelo sabor intenso e fama afrodisíaca.', 'centro_oeste', 'MT', '{"ings":[{"n":"Piranhas limpas inteiras","a":"4 unidades"},{"n":"Mandioca amassada cozida","a":"1 xícara"},{"n":"Tomate, cebola, pimentão","a":"a gosto"},{"n":"Coentro, cheiro-verde, pimenta-de-cheiro","a":"a gosto"},{"n":"Alho, limão, azeite, sal","a":"a gosto"}],"steps":["Cozinhe as piranhas em 2 litros de água com sal e limão por 20 min.","Coe o caldo; desfie a carne descartando espinhos (com MUITA atenção).","Em outra panela, refogue cebola, alho, pimentão e tomate em azeite.","Acrescente o caldo coado e a mandioca amassada para engrossar.","Junte a carne desfiada e cozinhe mais 10 min.","Finalize com coentro e pimenta-de-cheiro; sirva fumegante."],"tip":"Espinhos de piranha são finíssimos e perigosos — coe o caldo em pano de prato limpo."}'::jsonb),
  ('frango_caipira_guariroba', 'Frango Caipira com Guariroba', '🍗', 'Almoço · Goiano', '1h15', 'Frango caipira ensopado com guariroba refogada — combinação amarga-doce do cerrado.', 'centro_oeste', 'GO', '{"ings":[{"n":"Frango caipira em pedaços","a":"800 g"},{"n":"Guariroba picada","a":"1 xícara"},{"n":"Cebola, alho, tomate","a":"a gosto"},{"n":"Açafrão, cheiro-verde, pimenta","a":"a gosto"},{"n":"Banha de porco ou óleo","a":"2 col sopa"}],"steps":["Ferva a guariroba em 2 águas (10 min cada) para reduzir o amargor.","Tempere o frango com alho, sal, pimenta e açafrão; deixe 20 min.","Doure os pedaços na banha; acrescente cebola e tomate.","Cubra com água morna e cozinhe tampado por 40 min.","Adicione a guariroba e cozinhe mais 15 min até o caldo reduzir.","Finalize com cheiro-verde."],"tip":"Guariroba é o broto da palmeira — dessalgar direito é o que separa o prato bom do ruim."}'::jsonb),
  ('galinha_caipira_ensopada', 'Galinha Caipira Ensopada', '🐔', 'Almoço · Tradicional', '1h30', 'Galinha caipira cozida lentamente em caldo próprio com cebola, alho e colorau.', 'centro_oeste', 'GO', '{"ings":[{"n":"Galinha caipira em pedaços","a":"1,2 kg"},{"n":"Cebola, alho, tomate, pimentão","a":"a gosto"},{"n":"Colorau (urucum)","a":"1 col sopa"},{"n":"Cheiro-verde, louro","a":"a gosto"},{"n":"Sal, pimenta, óleo","a":"a gosto"}],"steps":["Tempere os pedaços com alho, sal, pimenta e colorau; deixe 30 min.","Doure bem em panela de pressão com um fio de óleo.","Junte cebola, pimentão e tomate; refogue por 5 min.","Cubra com água fervente e adicione folhas de louro.","Cozinhe em pressão por 40 min (galinha caipira é mais rija).","Abra a panela, ajuste o sal e reduza o caldo se necessário.","Finalize com cheiro-verde e sirva com arroz branco."],"tip":"Galinha caipira pede 40+ min de pressão — frango de granja fica desfiando em 20 min."}'::jsonb),
  ('frango_assado_batata_doce', 'Frango Assado com Batata-Doce', '🍗', 'Jantar · Fit', '50 min', 'Peito de frango assado com batata-doce em cubos — opção balanceada pós-treino.', 'centro_oeste', 'GO', '{"ings":[{"n":"Peito de frango em filés","a":"400 g"},{"n":"Batata-doce em cubos médios","a":"400 g"},{"n":"Alho, alecrim, páprica","a":"a gosto"},{"n":"Azeite, sal, pimenta, limão","a":"a gosto"}],"steps":["Tempere o frango com limão, alho, páprica e alecrim; deixe 20 min.","Espalhe a batata-doce numa assadeira regada com azeite, sal e alecrim.","Disponha os filés de frango por cima.","Cubra com papel alumínio e leve ao forno a 200 °C por 25 min.","Retire o alumínio e doure por mais 15 min.","Sirva com salada verde."],"tip":"Corte os cubos de batata em tamanho uniforme (~3cm) para assar por igual."}'::jsonb),
  ('omelete_queijo_minas', 'Omelete de Queijo Minas', '🍳', 'Jantar · Rápido', '10 min', 'Omelete rústico com queijo minas fresco em cubos — perfeito pra jantar leve.', 'centro_oeste', 'DF', '{"ings":[{"n":"Ovos caipiras","a":"3 unidades"},{"n":"Queijo minas fresco em cubos","a":"80 g"},{"n":"Cebolinha picada","a":"1 col sopa"},{"n":"Manteiga","a":"1 col sopa"},{"n":"Sal, pimenta-do-reino","a":"a gosto"}],"steps":["Bata os ovos com sal, pimenta e cebolinha.","Aqueça a manteiga em frigideira antiaderente em fogo médio.","Despeje os ovos; quando começar a firmar, distribua o queijo em cubos.","Dobre ao meio e cozinhe mais 1 min.","Sirva imediatamente com salada de alface e tomate."],"tip":"Fogo médio-baixo — omelete queimado por fora e cru por dentro vem de fogo alto demais."}'::jsonb),
  ('arroz_carne_seca', 'Arroz com Carne Seca', '🍚', 'Jantar · Tradicional', '50 min', 'Arroz refogado com carne seca desfiada — rápido, substancioso, sabor de roça.', 'centro_oeste', 'MT', '{"ings":[{"n":"Carne seca dessalgada e desfiada","a":"250 g"},{"n":"Arroz branco cru","a":"1 xícara"},{"n":"Cebola, alho, cebolinha","a":"a gosto"},{"n":"Banha ou óleo, pimenta","a":"a gosto"}],"steps":["Dessalgue a carne em 2 águas; cozinhe em pressão 30 min; desfie.","Refogue cebola e alho na banha em panela larga.","Acrescente a carne desfiada e doure por 5 min.","Junte o arroz lavado e misture bem.","Cubra com 2 xícaras de água fervente; cozinhe tampado por 15 min.","Finalize com cebolinha e pimenta moída na hora."],"tip":"Farofa leve de cebola e banha por cima é o acompanhamento clássico."}'::jsonb),
  ('arroz_sua_de_porco', 'Arroz com Suã de Porco', '🍖', 'Almoço · Tradicional', '1h15', 'Arroz cozido com suã (espinhaço) de porco, cupim e temperos — prato denso e saboroso.', 'centro_oeste', 'MT', '{"ings":[{"n":"Suã de porco em pedaços","a":"500 g"},{"n":"Cupim bovino em cubos (opcional)","a":"200 g"},{"n":"Arroz branco cru","a":"1,5 xícaras"},{"n":"Cebola, alho, pimentão, tomate","a":"a gosto"},{"n":"Colorau, louro, sal, pimenta","a":"a gosto"}],"steps":["Tempere a suã (e o cupim) com alho, sal, pimenta e colorau; deixe 30 min.","Doure a carne em panela de pressão com um fio de óleo.","Acrescente cebola, alho, tomate, pimentão e louro; refogue.","Cubra com água e cozinhe em pressão por 30 min.","Retire a pressão; acrescente o arroz lavado e mais 2 xícaras de água quente.","Cozinhe tampado (sem pressão) por 15 min até o arroz secar.","Descanse 5 min antes de servir."],"tip":"Suã tem muito osso e gordura saborosa — não descarte o caldo de cozinhar, use pra hidratar o arroz."}'::jsonb),
  ('sopa_mandioca_carne_seca', 'Sopa de Mandioca com Carne Seca', '🍲', 'Jantar · Confortável', '45 min', 'Sopa cremosa de mandioca amassada com carne seca desfiada — puro aconchego de fogão.', 'centro_oeste', 'MT', '{"ings":[{"n":"Mandioca descascada em pedaços","a":"600 g"},{"n":"Carne seca dessalgada e desfiada","a":"200 g"},{"n":"Cebola, alho, cheiro-verde","a":"a gosto"},{"n":"Caldo (de galinha ou da carne seca)","a":"1 litro"},{"n":"Sal, pimenta, manteiga","a":"a gosto"}],"steps":["Cozinhe a mandioca em água com sal até desmanchar (25 min).","Bata metade da mandioca no liquidificador com 2 conchas de caldo.","Refogue cebola e alho na manteiga; junte a carne seca desfiada.","Acrescente a mandioca batida, a mandioca em pedaços e o restante do caldo.","Cozinhe em fogo baixo por 10 min mexendo de vez em quando.","Finalize com cheiro-verde e pimenta moída."],"tip":"Passe a mandioca cozida por um espremedor — fica muito mais cremosa que no liquidificador."}'::jsonb),
  ('sopa_feijao_linguica', 'Sopa de Feijão com Mandioca e Linguiça', '🫘', 'Jantar · Rústico', '1h', 'Caldo reforçado de feijão com mandioca e linguiça calabresa — noite fria pede.', 'centro_oeste', 'GO', '{"ings":[{"n":"Feijão carioca cozido com caldo","a":"2 xícaras"},{"n":"Mandioca em cubos","a":"300 g"},{"n":"Linguiça calabresa em rodelas","a":"200 g"},{"n":"Cebola, alho, louro, cheiro-verde","a":"a gosto"},{"n":"Sal, pimenta","a":"a gosto"}],"steps":["Doure a linguiça em panela funda; escorra o excesso de gordura.","Refogue cebola e alho na mesma panela.","Junte o feijão cozido com caldo, a mandioca e louro.","Cubra com 1 litro de água morna; cozinhe por 25 min até a mandioca amolecer.","Amasse alguns pedaços contra a panela para engrossar o caldo.","Ajuste o sal e finalize com cheiro-verde."],"tip":"Um pedacinho de bacon defumado no refogado turbina o caldo sem pesar."}'::jsonb),
  ('canja_galinha', 'Canja de Galinha com Legumes', '🍲', 'Jantar · Reconfortante', '45 min', 'Caldo leve de galinha com arroz, cenoura e batata — clássico de fim de dia pesado.', 'centro_oeste', 'GO', '{"ings":[{"n":"Peito de galinha caipira","a":"300 g"},{"n":"Arroz cru","a":"1/3 xícara"},{"n":"Cenoura em cubinhos","a":"1 unidade"},{"n":"Batata em cubinhos","a":"1 unidade"},{"n":"Cebola, alho, cheiro-verde, louro","a":"a gosto"}],"steps":["Cozinhe a galinha em 1,5 l de água com cebola, alho e louro por 30 min.","Retire a galinha, desfie e reserve; mantenha o caldo no fogo.","Adicione o arroz ao caldo e cozinhe por 8 min.","Junte cenoura e batata; cozinhe mais 10 min.","Devolva a galinha desfiada à panela e aqueça por 3 min.","Finalize com cheiro-verde e uma pitada de pimenta."],"tip":"Escolha peito com pele e osso — o caldo fica muito mais saboroso e reconfortante."}'::jsonb),
  ('peixe_grelhado_legumes', 'Peixe Grelhado com Legumes', '🐟', 'Jantar · Leve', '25 min', 'Posta de pacu ou pintado grelhada rapidamente, servida com legumes salteados.', 'centro_oeste', 'MT', '{"ings":[{"n":"Posta de pacu ou pintado","a":"300 g"},{"n":"Abobrinha em meia-lua","a":"1 unidade"},{"n":"Cenoura em palitos","a":"1 unidade"},{"n":"Pimentão em tiras","a":"1/2 unidade"},{"n":"Alho, limão, azeite, sal, pimenta","a":"a gosto"}],"steps":["Tempere o peixe com limão, sal, pimenta e alho; deixe 10 min.","Aqueça uma frigideira/chapa com pouquíssimo azeite.","Grelhe o peixe 3 min cada lado (sem mexer para formar crosta).","Na mesma chapa, salteie os legumes por 5 min em fogo alto.","Finalize com um fio de azeite cru e limão."],"tip":"Seque bem a posta em papel-toalha antes de grelhar — água na superfície impede a crosta."}'::jsonb)
