-- Migration 0024: seed de receitas Centro-oeste (gerado por scripts/generate-recipes-seed.mjs)
-- 22 receitas curadas para region='centro_oeste'. UPSERT por slug.

delete from public.recipes where region = 'centro_oeste';

on conflict (slug) do update set
  title = excluded.title,
  icon = excluded.icon,
  category = excluded.category,
  time_label = excluded.time_label,
  description = excluded.description,
  region = excluded.region,
  state = excluded.state,
  data = excluded.data;
